async (params, browser) => {
  // Open WhatsApp Web
  await browser.open('https://web.whatsapp.com')

  // Wait for chat list
  await browser.waitForSelector('div#pane-side, div[data-testid=\'chatlist\']', 30000)

  // Let chat list render
  await browser.wait(3000)

  // Extract chat list
  const result = await browser.evaluate(`const contacts = []; const chatItems = document.querySelectorAll('#pane-side [data-testid="list-item"], #pane-side [data-testid="cell-frame-container"], div[data-testid="chatlist"] div[tabindex]'); for (let i = 0; i < Math.min(chatItems.length, 30); i++) { const item = chatItems[i]; const nameEl = item.querySelector('span[title], [data-testid="cell-frame-title"] span'); const msgEl = item.querySelector('span[data-testid="last-msg-status"], span.selectable-text'); const timeEl = item.querySelector('div._amk6, [data-testid="cell-frame-secondary"]'); const unreadEl = item.querySelector('span[data-testid="icon-unread-count"], .unread-count'); contacts.push({ name: nameEl?.getAttribute('title') || nameEl?.textContent?.trim() || '', last_message: msgEl?.textContent?.trim()?.substring(0, 100) || '', time: timeEl?.textContent?.trim() || '', unread: unreadEl?.textContent?.trim() || '' }); } return { result_count: contacts.length, contacts: contacts }`)

  return result
}
